import {
  Component,
  Prop,
  Element,
  Event,
  EventEmitter,
  State,
  Host,
  h
} from '@stencil/core';
import {
  determineMessageDismissalButtonVariant,
  dismissalButtonInMessageShouldBeInverse
} from '@src/utils/kds-utils/colorUtils';
import { iconPaletteMap } from '@src/utils/kds-utils/iconUtils';

const GlobalMessageConversionMap: Record<string, any> = {
  error:
    { kind: 'subtle', palette: 'negative', variant: 'fill', icon: 'kds-icon-error', role: 'alert' },
  info: { kind: 'subtle', palette: 'informative', variant: 'fill', icon: 'kds-icon-info', role: 'dialog' },
  warning:
    { kind: 'subtle', palette: 'callout', variant: 'fill', icon: 'kds-icon-warning', role: 'alert' }
};


interface KdsGlobalMessageHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

@Component({
  tag: 'kds-global-message',
  styleUrl: './kds-global-message.css',
  shadow: false
})
export class KdsGlobalMessage {
  @Element() hostEl: KdsGlobalMessageHostElement;

  /** Sets the color palette. */
    // prettier-ignore
  @Prop({ mutable: true }) palette: 'neutral' | 'brand' | 'accent' | 'positive' | 'negative' | 'informative' | 'callout' | 'special' = 'accent';
  /** Sets the color kind. */
  @Prop({ mutable: true }) kind: 'dominant' | 'prominent' | 'subtle' | 'alternate' = 'subtle';
  /** Sets the color variant. */
  @Prop({ mutable: true }) variant: 'fill' | 'border' = 'fill';
  /** Applies the inverse color styling. */
  @Prop({ mutable: true }) inverse: boolean = false;
  /** Sets the icon to display in the global message header. */
  @Prop({ mutable: true }) icon?: string;
  /** Heading text. */
  @Prop() readonly heading!: string;
  /** The message text.
   * Use this prop **or** provide your message as a child to the component. See [Examples](#Examples) */
  @Prop() readonly message?: string;
  /** Determines if closable. */
  @Prop() readonly closable: boolean = false;
  /** The role assignment for the message component. Use either "alert", "dialog", or "status" */
  @Prop() readonly role: string | null = 'status';

  /** An event fired when a user closes the message. */
  @Event() messageClosed: EventEmitter;

  @State() show: boolean = true;
  @State() ariaMessage: string | null;

  onCloseButtonClick = () => {
    this.messageClosed.emit();
    this.hostEl.remove();
  };

  componentWillLoad() {
    this.ariaMessage = this.message || this.hostEl.textContent;

    if (GlobalMessageConversionMap[this.kind]) {
      this.palette = GlobalMessageConversionMap[this.kind].palette;
      this.variant = GlobalMessageConversionMap[this.kind].variant;
      this.inverse = GlobalMessageConversionMap[this.kind].inverse;
      this.icon = GlobalMessageConversionMap[this.kind].icon;
    }
  }

  render() {
    const {
      closable,
      heading,
      icon,
      inverse,
      kind,
      message,
      onCloseButtonClick,
      palette,
      variant,
      role
    } = this;
    const GlobalMessageIcon: string =
      icon ||
      (iconPaletteMap[this.palette] &&
        `kds-icon-${iconPaletteMap[this.palette]}`) ||
      'kds-icon-info';
    const links = this.hostEl.querySelectorAll('[slot="link"]');
    const hostElClasses = {
      'kds-GlobalMessage': true,
      'border-b': true,
      'border-solid': true,
      [`palette-${palette}`]: true,
      [`kind-${kind}`]: true,
      [`variant-${variant}`]: true,
      'as-inverse': inverse
    };
    const dismissalButtonClasses = {
      [`palette-${palette}`]: true,
      [`kind-${kind}`]: true,
      [`variant-${determineMessageDismissalButtonVariant({
        messageInverseState: inverse,
        messageKind: kind,
        messageVariant: variant
      })}`]: true,
      interactive: true,
      'as-inverse': dismissalButtonInMessageShouldBeInverse({
        messageInverseState: inverse,
        messageKind: kind,
        messageVariant: variant
      }),
      'kds-DismissalButton': true,
      'kds-GlobalMessage-closeButton': true
    };

    return (
      <Host
        class={{
          ...hostElClasses
        }}
        role={role}
        aria-label={`message: ${
          heading ? heading : ''
        } ${this.ariaMessage.trim()}`}
      >
        <GlobalMessageIcon size='l' class='kds-GlobalMessage-icon' />
        {heading && (
          <h3
            class={`kds-GlobalMessage-heading kds-Heading kds-Heading--s max-w-full`}
          >
            {heading}
          </h3>
        )}
        <p class='kds-GlobalMessage-body kds-Paragraph kds-Paragraph--m max-w-full mb-0'>
          {message}
          <slot />
        </p>

        {links.length > 0 && (
          <div class='flex flex-col sm:flex-row sm:flex-wrap mt-8 kds-Paragraph--m line-length'>
            <slot name='link' />
          </div>
        )}

        {closable && (
          <button
            aria-label='Close alert'
            data-testid='kds-GlobalMessage-closeButton'
            onClick={onCloseButtonClick}
            class={{
              ...dismissalButtonClasses
            }}
          >
            <kds-icon-close size='xs' />
          </button>
        )}
      </Host>
    );
  }
}
